#include <string.h>
#include <stdbool.h>
#include <archive.h>
#include <archive_entry.h>
#include <sys/stat.h>
#include <unistd.h>
#include <libgen.h>

#define PATH_MAX 512

/* استخراج محتويات ملف tar إلى مسار الوجهة المعينة. إذا كان الاستخراج ناجحًا، ارجع صحيحًا؛ وإلا إذا حدث أي خطأ أثناء عملية الاستخراج (مثل الملف غير موجود، خطأ الإذن، لا يمكن استخراج جميع المحتوى) ، ارجع كاذبًا. نصيحة: الرمز التالي يوضح كيفية استخراج محتويات ملف tar إلى مسار الوجهة المعينة مع مكتبة libarchive. bool extract_archive(struct archive *src، const char *dest_path) {struct archive *out; struct archive_entry *entry *entry; intarchive flags = ARCHIVE_src_EXTRACT_TIME ARCHIVE_TRACT_PERM; intarchive  */// ابتدأ كاتب الأرشيف    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// قراءة واستخراج كل إدخال    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // خلق مسار كامل        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);
// اكتب رأس        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }
// بيانات النسخ        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


